// 无数据时返回占位项，保证州/城市下拉可点击、可选
const FALLBACK_REGION = { value: '_', label: '—' }
const FALLBACK_CITY = { value: '_', label: '—' }

export function getRegions(countryCode: string): { value: string; label: string }[] {
  const regions = COUNTRY_REGIONS[countryCode]
  if (!regions || regions.length === 0) return [FALLBACK_REGION]
  return regions.map((r) => ({ value: r.value, label: r.label }))
}

export function getCities(countryCode: string, regionValue: string): { value: string; label: string }[] {
  const regions = COUNTRY_REGIONS[countryCode]
  if (!regions) return [FALLBACK_CITY]
  const region = regions.find((r) => r.value === regionValue)
  if (!region || !region.cities || region.cities.length === 0) return [FALLBACK_CITY]
  return region.cities
}

/** 校验：国家列表中的每个国家在 COUNTRY_REGIONS 中均有完整数据，且无重复 region.value、无空 cities */
export function validateCountryRegions(countryCodes: string[]): { ok: boolean; missing: string[]; emptyOrInvalid: string[]; duplicateRegionValues: { country: string; value: string }[] } {
  const missing: string[] = []
  const emptyOrInvalid: string[] = []
  const duplicateRegionValues: { country: string; value: string }[] = []
  for (const code of countryCodes) {
    const regions = COUNTRY_REGIONS[code]
    if (!regions || regions.length === 0) {
      missing.push(code)
      continue
    }
    const seen = new Set<string>()
    for (const r of regions) {
      if (r.value === '_' || r.label === '—') emptyOrInvalid.push(code)
      if (seen.has(r.value)) duplicateRegionValues.push({ country: code, value: r.value })
      seen.add(r.value)
      if (!r.cities || r.cities.length === 0) emptyOrInvalid.push(code)
    }
  }
  return {
    ok: missing.length === 0 && emptyOrInvalid.length === 0 && duplicateRegionValues.length === 0,
    missing,
    emptyOrInvalid: [...new Set(emptyOrInvalid)],
    duplicateRegionValues,
  }
}
